//  NAVIGATION
// ═══════════════════════════════════════════════
function showScreen(id){
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  window.scrollTo(0,0);
}

function goHome(){
  showScreen('screen-landing');
  userData={};stepIdx=0;
}

function startOption(n){
  if(!API_KEY){
    toast('Please enter your Gemini API key (top right)');
    document.getElementById('api-key-btn').click();
    return;
  }
  currentOption = n;
  const flow = FLOWS[n];
  userData={};stepIdx=0;
  flowSteps = flow.steps;
  // set briefing header
  document.getElementById('brief-title-label').textContent = flow.label;
  document.getElementById('brief-title-label').style.color = flow.color;
  // clear chat
  document.getElementById('chat-scroll').innerHTML='';
  // build progress dots
  const pd = document.getElementById('progress-dots');
  pd.innerHTML = flowSteps.map((_,i)=>`<div class="prog-dot" id="pdot-${i}"></div>`).join('');
  showScreen('screen-briefing');
  hideInputZone();
  // intro message after delay
  setTimeout(()=>{
    addBubble('mentor', flow.intro, ()=>{
      setTimeout(()=>askStep(0), 600);
    });
  },400);
}

// ═══════════════════════════════════════════════
//  CHAT ENGINE
// ═══════════════════════════════════════════════
function addBubble(who, msg, cb){
  const scroll = document.getElementById('chat-scroll');
  const div = document.createElement('div');
  div.className = `chat-bubble ${who==='user'?'user-msg':''}`;

  // typing dots for mentor
  if(who==='mentor'){
    div.innerHTML=`
      <div class="avatar" style="background:none;border:3px solid var(--ink);"><img src="data:image/jpeg;base64," style="width:100%;height:100%;object-fit:cover;border-radius:50%;"></div>
      <div class="bubble-body"><div class="typing-dots">
        <div class="typing-dot"></div><div class="typing-dot"></div><div class="typing-dot"></div>
      </div></div>`;
    scroll.appendChild(div);
    scrollBottom();
    setTimeout(()=>{
      div.querySelector('.bubble-body').innerHTML = formatMsg(msg);
      scrollBottom();
      if(cb) cb();
    }, msg.length < 80 ? 800 : 1400);
  } else {
    div.innerHTML=`
      <div class="bubble-body">${escapeHtml(msg)}</div>
      <div class="avatar" style="background:none;border:3px solid var(--ink);"><img src="data:image/jpeg;base64," style="width:100%;height:100%;object-fit:cover;border-radius:50%;"></div>`;
    scroll.appendChild(div);
    scrollBottom();
    if(cb) cb();
  }
}

function formatMsg(s){
  return s.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>')
          .replace(/\n/g,'<br>');
}

function escapeHtml(s){
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function scrollBottom(){
  const s = document.getElementById('chat-scroll');
  setTimeout(()=>s.scrollTop=s.scrollHeight,50);
}

function askStep(idx){
  if(idx >= flowSteps.length){ runAI(); return; }
  stepIdx = idx;
  // update progress dots
  document.querySelectorAll('.prog-dot').forEach((d,i)=>{
    d.className = 'prog-dot' + (i<idx?' done':i===idx?' active':'');
  });
  const step = flowSteps[idx];
  addBubble('mentor', step.q, ()=>{ setTimeout(()=>showInputFor(step),300); });
}

function showInputFor(step){
  const zone = document.getElementById('input-zone');
  const label = document.getElementById('input-label');
  const inp = document.getElementById('chat-inp');
  const qopts = document.getElementById('quick-opts');
  const sliderWrap = document.getElementById('slider-wrap');
  const sendBtn = document.getElementById('send-btn');

  zone.classList.remove('hidden');
  qopts.innerHTML='';
  inp.value='';

  if(step.type==='slider'){
    label.textContent = 'Drag to set your age:';
    inp.style.display='none';
    sendBtn.style.display='block';
    sliderWrap.classList.remove('hidden');
    document.getElementById('age-slider').value=28;
    document.getElementById('slider-val').textContent=28;
  } else if(step.type==='quick'){
    label.textContent = 'Choose one:';
    inp.style.display='none';
    sendBtn.style.display='none';
    sliderWrap.classList.add('hidden');
    step.opts.forEach(o=>{
      const b=document.createElement('button');
      b.className='qopt';b.textContent=o;
      b.onclick=()=>selectQuick(o);
      qopts.appendChild(b);
    });
  } else {
    label.textContent = 'Your answer:';
    inp.style.display='block';
    sendBtn.style.display='block';
    sliderWrap.classList.add('hidden');
    inp.placeholder = step.placeholder || 'Type here...';
    inp.focus();
  }
}

function hideInputZone(){
  document.getElementById('input-zone').classList.add('hidden');
}

function selectQuick(val){
  hideInputZone();
  recordAnswer(val);
}

function submitAnswer(){
  const step = flowSteps[stepIdx];
  let val;
  if(step.type==='slider'){
    val = document.getElementById('age-slider').value + ' years old';
    userData._age_raw = document.getElementById('age-slider').value;
  } else {
    val = document.getElementById('chat-inp').value.trim();
    if(!val){ toast('Please enter an answer!'); return; }
  }
  hideInputZone();
  recordAnswer(val);
}

function recordAnswer(val){
  const step = flowSteps[stepIdx];
  userData[step.key] = val;
  addBubble('user', val, ()=>{
    setTimeout(()=>askStep(stepIdx+1), 400);
  });
}

// ═══════════════════════════════════════════════
//  AI AGENT CALL
// ═══════════════════════════════════════════════
async function runAI(){
  hideInputZone();
  // all dots done
  document.querySelectorAll('.prog-dot').forEach(d=>d.className='prog-dot done');
  addBubble('mentor', `Got it! Give me a moment to analyze your information...`, ()=>{});
  setTimeout(()=>document.getElementById('loading-overlay').classList.add('show'),600);

  const prompt = buildPrompt();
  try{
    // Step 1: network request
    let res;
    try{
      res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${API_KEY}`,{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body: JSON.stringify({
          contents:[{parts:[{text:prompt}]}],
          generationConfig:{maxOutputTokens:1800}
        })
      });
    } catch(networkErr){
      throw new Error('Network error — check your internet connection and try again.');
    }

    // Step 2: parse response body safely
    let data;
    try{
      data = await res.json();
    } catch(parseErr){
      throw new Error(`Server returned an unreadable response (HTTP ${res.status}). Try again shortly.`);
    }

    // Step 3: surface API-level errors (quota, invalid key, bad request, etc.)
    if(data.error){
      const code = data.error.code || res.status;
      const msg  = data.error.message || 'Unknown API error';
      if(code === 429 || msg.toLowerCase().includes('quota')){
        throw new Error('Quota exceeded on your Gemini API key. Please check your plan & billing at ai.google.dev, then try again.');
      }
      if(code === 400){ throw new Error(`Bad request: ${msg}`); }
      if(code === 401 || code === 403){ throw new Error('Invalid or unauthorized API key. Please re-enter your Gemini API key.'); }
      if(code === 404){ throw new Error('API endpoint not found (404). The model name may have changed — please refresh the page.'); }
      throw new Error(`API error ${code}: ${msg}`);
    }

    // Step 4: safely extract text — candidates may be missing even on a 200
    if(!data.candidates || !Array.isArray(data.candidates) || data.candidates.length === 0){
      throw new Error('The AI returned an empty response. This can happen when content is blocked or the request times out. Please try again.');
    }
    const candidate = data.candidates[0];
    if(!candidate.content || !candidate.content.parts || candidate.content.parts.length === 0){
      const reason = candidate.finishReason || 'unknown';
      throw new Error(`The AI response was empty (finish reason: ${reason}). Please try again.`);
    }
    const text = candidate.content.parts.map(p => p.text || '').join('');
    if(!text.trim()){
      throw new Error('The AI returned blank text. Please try again.');
    }

    document.getElementById('loading-overlay').classList.remove('show');

    // Step 5: parse JSON from AI text
    let parsed;
    try{
      const clean = text.replace(/```json|```/g,'').trim();
      parsed = JSON.parse(clean);
    } catch(e){
      parsed = { raw: text };
    }
    showReveal(parsed);

  } catch(err){
    document.getElementById('loading-overlay').classList.remove('show');
    addBubble('mentor', `Something went wrong: ${err.message}`);
    toast('Error — see chat for details');
  }
}

