function renderHealthReveal(d,body){
  document.getElementById('reveal-title').textContent = 'FINANCIAL AURA SCAN COMPLETE';
  const score = d.overallScore||0;
  const dims = d.dimensions||[];
  const badge = d.badge||{};
  const actions = d.topActions||[];
  const scoreColor = score>=80?'#2E8B57':score>=55?'#F5B800':'#CC2200';
  const circumference = 2*Math.PI*80; // r=80
  const dashOffset = circumference - (score/100)*circumference;
  body.innerHTML=`
  <div class="health-wrap">
    <h2 style="font-family:'Bangers',cursive;font-size:28px;letter-spacing:2px;margin-bottom:20px;">YOUR MONEY HEALTH SCORE</h2>
    <!-- score ring -->
    <div class="score-ring-wrap">
      <svg class="score-ring" width="200" height="200" viewBox="0 0 200 200">
        <circle cx="100" cy="100" r="80" fill="none" stroke="#eee" stroke-width="14"/>
        <circle cx="100" cy="100" r="80" fill="none" stroke="${scoreColor}" stroke-width="14"
          stroke-dasharray="${circumference}" stroke-dashoffset="${dashOffset}"
          stroke-linecap="round" transform="rotate(-90 100 100)"
          style="transition:stroke-dashoffset 2s ease;"/>
      </svg>
      <div class="score-inner">
        <div class="score-big" style="color:${scoreColor}">${score}</div>
        <div class="score-tag" style="color:${scoreColor}">/100</div>
      </div>
    </div>
    <div style="font-family:'Cinzel',serif;font-size:22px;letter-spacing:2px;margin-bottom:6px;font-weight:700;">${d.rank||'Financial Warrior'}</div>

    <!-- 6 dimensions -->
    <div class="dims-grid">
      ${dims.map(dim=>`
        <div class="dim-card">
          <div class="dim-name">${dim.name}</div>
          <div class="dim-score" style="color:${dim.color||'#1a1a1a'}">${dim.score}</div>
          <div class="dim-bar-bg">
            <div class="dim-bar-fill" style="width:0%;background:${dim.color||'#2E8B57'}" data-width="${dim.score}"></div>
          </div>
          <div class="dim-feedback">${dim.feedback||''}</div>
        </div>`).join('')}
    </div>

    <!-- top actions -->
    ${actions.length?`
    <div style="border:3px solid var(--ink);border-radius:14px;padding:20px;margin:20px 0;background:#fff;text-align:left;">
      <div style="font-family:'Bangers',cursive;font-size:20px;letter-spacing:2px;margin-bottom:12px;"> YOUR TOP 3 ACTIONS</div>
      ${actions.map((a,i)=>`
        <div style="display:flex;gap:12px;align-items:flex-start;margin-bottom:10px;">
          <div style="background:var(--gold);border:2px solid var(--ink);border-radius:50%;width:28px;height:28px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-family:'Bangers',cursive;font-size:14px;">${i+1}</div>
          <div style="font-size:13.5px;padding-top:3px;">${a}</div>
        </div>`).join('')}
    </div>`:''}

    <!-- WA Badge -->
    <div class="wa-badge">
      <div class="badge-rank-txt"> EVOLUTION BADGE</div>
      
      <div class="badge-title-txt">${badge.title||d.rank||'SAVER'}</div>
      <div class="badge-sub-txt">${badge.subtitle||'Financial Warrior'}</div>
      <div style="font-size:11px;color:#888;margin-top:4px;">FinFuture Money Health Score: ${score}/100</div>
    </div>

    <div class="reveal-actions">
      <button class="ract-btn whatsapp" onclick="shareWhatsApp('${(badge.shareText||'I scored '+score+'/100 on my Money Health Score on FinFuture AI!').replace(/'/g,"\\'")}')">Share Badge on WhatsApp</button>
      <button class="ract-btn secondary" onclick="startOption(3)">Retake Quiz</button>
      <button class="ract-btn primary" onclick="goHome()">Back to Missions</button>
    </div>
  </div>`;

  // animate bars
  setTimeout(()=>{
    document.querySelectorAll('.dim-bar-fill').forEach(el=>{
      el.style.width = el.dataset.width + '%';
    });
  },300);
}

function shareWhatsApp(text){
  window.open('https://wa.me/?text='+encodeURIComponent(text),'_blank');
}

// ═══════════════════════════════════════════════
//  TOAST UTILITY
// ═══════════════════════════════════════════════
function toast(msg){
  const t=document.getElementById('toast');
  t.textContent=msg;t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'),2800);
}


// Close API modal when clicking outside
document.addEventListener('click', function(e){
  const modal = document.getElementById('api-modal');
  const btn = document.getElementById('api-key-btn');
  if(modal && modal.classList.contains('show') && !modal.contains(e.target) && e.target !== btn){
    modal.classList.remove('show');
  }
});

// animate floats on landing
document.querySelectorAll('.doodle-item').forEach((el,i)=>{
  el.style.animation=`floatBag ${3+i%3}s ease-in-out infinite`;
  el.style.animationDelay=`${i*0.4}s`;
});

// Add float keyframe for doodles
const styleEl = document.createElement('style');
styleEl.textContent = `
  @keyframes floatBag {
    0%,100%{transform:translateY(0) rotate(0);}
    50%{transform:translateY(-12px) rotate(4deg);}
  }
`;
document.head.appendChild(styleEl);
